// Body llega como string por mode: 'no-cors', hay que parsearlo
const raw = $input.first().json.body;
const body = typeof raw === 'string' ? JSON.parse(raw) : raw;

const nombre = (body.nombre || '').trim();
const apellidos = (body.apellidos || '').trim();
const nombreCompleto = `${nombre} ${apellidos}`.trim();

return [{
  json: {
    nombre,
    apellidos,
    nombreCompleto,
    email: (body.email || '').trim().toLowerCase(),
    telefono: (body.telefono || '').trim(),
    edad: body.edad || '',
    nivel: body.nivel || 'no especificado',
    mensaje: body.mensaje || '',
    evento: 'Surfin Skate Jam 2026',
    fecha_inscripcion: new Date().toISOString(),
    tipo: 'rider'
  }
}];

// Tags nuevos del formulario — incluye edad y mensaje como tags
const nivel = $('Procesar Datos Rider').item.json.nivel;
const edad = $('Procesar Datos Rider').item.json.edad;
const mensaje = $('Procesar Datos Rider').item.json.mensaje;

const nuevosTags = [
  'skatejam-rider',
  'nivel-' + nivel,
  'evento-2026',
  'edad-' + edad
];

// Añadir mensaje solo si existe y no está vacío
if (mensaje && mensaje.trim() !== '') {
  nuevosTags.push('mensaje-' + mensaje.trim().toLowerCase().replace(/\s+/g, '-'));
}

// Tags existentes en GHL (si el contacto ya existe)
const contactoExistente = $input.first().json?.contacts?.[0];
const tagsExistentes = contactoExistente?.tags || [];

// Combinar sin duplicados
const tagsCombinados = [...new Set([...tagsExistentes, ...nuevosTags])];

return [{
  json: {
    ...$('Procesar Datos Rider').item.json,
    tags: tagsCombinados
  }
}];

